#include <bits/stdc++.h>
#define int long long
using namespace std;
int exgcd (int a, int b, int &x, int &y) {
	if (!b) {
		x = 1;
		y = 0;
		return a;
	}
	int res = exgcd (b, a % b, x , y), t;
	t = x;
	x = y;
	y = t - a / b * y;
	return res;
}
int p;
int power (int a, int b, int mod) {
	int sm;
	for (sm = 1; b; b >>= 1, a = a * a % mod) {
		if (b & 1) {
			sm = sm * a % mod; 
		}
	}
	return sm;
}
int fac (int n, int pi, int pk) {
	if (!n) {
		return 1;
	}
	int res = 1;
	for (register int i = 2; i <= pk; i++) {
		if (i % pi) {
			(res *= i) %= pk;
		}
	}
	res = power (res, n / pk, pk);
	for (register int i = 2; i <= n % pk; i++) {
		if (i % pi) {
			(res *= i) %= pk;
		}
	}
	return res * fac (n / pi, pi, pk) % pk;
}
int inv (int n, int mod) {
	int x, y;
	exgcd (n, mod, x, y);
	return (x += mod) > mod ? x - mod : x;
}
int CRT (int b, int mod) {
	return b * inv (p / mod, mod) % p * (p / mod) % p;
}
const int MAXN = 11;
static int n, m;
static int w[MAXN];
int C (int n, int m, int pi, int pk) {
	int up = fac (n, pi, pk), d1 = fac (m, pi, pk), d2 = fac (n - m, pi, pk);
	int k = 0;
	for (register int i = n; i; i /= pi) {
		k += i / pi;
	}
	for (register int i = m; i; i /= pi) {
		k -= i / pi;
	}
	for (register int i = n - m; i; i /= pi) {
		k -= i / pi;
	}
	return up * inv (d1, pk) % pk * inv (d2, pk) % pk * power (pi, k, pk) % pk;
}
int exlucus (int n, int m) {
    int res = 0, tmp = p, pk;
	static int lim = sqrt (p) + 5;
    for (register int i = 2; i <= lim; i++) {
		if (tmp % i == 0) {
        	pk = 1;
			while (tmp % i == 0) {
				pk *= i;
				tmp /= i;
			}
            (res += CRT (C (n, m, i, pk), pk)) %= p;
    	}
    }
	if (tmp > 1) {
		(res += CRT (C (n, m, tmp, tmp), tmp)) %= p;
	}
    return res;
}
signed main () {
